local  Advanceds= MemoryPool.newTable()

AdvancedConfig = {}

function AdvancedConfig:loadConfig()
    local temp = FileUtil.getConfigFromCsv("setting/Advanced.csv", 2)
    for _, Value in pairs(temp) do
        table.insert(Advanceds, {
            Id = tonumber(Value.n_id),
            Name = Value.s_name or "",
            Desc = Value.s_desc or "",
            Tips = Value.s_tips or "",
            BuyTips = Value.s_buyTips or "",
            Icon = Value.s_icon or "",
            Speed  = tonumber(Value.n_speed),
            Attack = tonumber(Value.n_attack),
            Workout = tonumber(Value.n_workout),
            MoneyType = tonumber(Value.n_moneyType),
            Price = tonumber(Value.n_price) or 0,
            Status = ItemBuyStatus.Lock, --购买状态
            speedEffect = StringUtil.split(Value.s_speedEffect, ","), --速度特效
            powerEffect = StringUtil.split(Value.s_powerEffect, ","), --力量特效
            killEffect = Value.s_killEffect or "", --击杀特效
        })
    end

    --LogUtil.log("AdvancedConfig:loadConfig " .. inspect.inspect(Advanceds))
end

function AdvancedConfig:getAdvanceds()
    return Advanceds
end

function AdvancedConfig:getAdvancedById(Id)

    for _, Value in pairs(Advanceds) do
        if Value.Id==Id then
            return Value
        end
    end
    return nil
end